// ─── Read request body and headers ──────────────────────────
const body = $json.body || $json;
const hdrs = $json.headers || {};

// ─── Secret validation ───────────────────────────────────────
// Fix: compare directly -- no conditional bypass.
const secret         = hdrs['x-brain-secret'] || hdrs['X-Brain-Secret'] || '';
const expectedSecret = 'n8n-sql-datacall-26';

if (secret !== expectedSecret) {
  return [{ json: {
    valid: false,
    query: null,
    error: 'ACCESS_DENIED: Request authentication failed. This data call cannot be executed.'
  }}];
}

// ─── Extract and clean the raw query ────────────────────────
const rawQuery = (body.query || '').trim().replace(/;+$/, '').trim();

if (!rawQuery) {
  return [{ json: {
    valid: false,
    query: null,
    error: 'INVALID_QUERY: No query was provided.'
  }}];
}

// ─── Rule 1: Must start with SELECT ─────────────────────────
if (!rawQuery.trimStart().toUpperCase().startsWith('SELECT')) {
  return [{ json: {
    valid: false,
    query: null,
    error: 'OPERATION_BLOCKED: Only SELECT (read) operations are permitted. The AI assistant does not have permission to insert, update, delete, or modify data.'
  }}];
}

// ─── Rule 2: No write operations (defense in depth) ─────────
if (/\b(INSERT|UPDATE|DELETE|DROP|CREATE|ALTER|TRUNCATE|REPLACE|RENAME|CALL|EXEC|EXECUTE)\b/i.test(rawQuery)) {
  return [{ json: {
    valid: false,
    query: null,
    error: 'OPERATION_BLOCKED: Write operations (INSERT, UPDATE, DELETE, DROP, etc.) are not permitted. The AI assistant has read-only access.'
  }}];
}

// ─── Rule 3: No UNION (injection bypass vector) ──────────────
if (/\bUNION\b/i.test(rawQuery)) {
  return [{ json: {
    valid: false,
    query: null,
    error: 'OPERATION_BLOCKED: UNION queries are not permitted. Inform the user that this type of query cannot be executed, and suggest they rephrase their question about clinic data.'
  }}];
}

// ─── Rule 4: No SQL comments (injection cover) ───────────────
if (/--/.test(rawQuery) || /\/\*/.test(rawQuery) || /\*\//.test(rawQuery)) {
  return [{ json: {
    valid: false,
    query: null,
    error: 'OPERATION_BLOCKED: SQL comments are not permitted in queries. Please rephrase your request.'
  }}];
}

// ─── Rule 5: No stacked queries ──────────────────────────────
if (/;/.test(rawQuery)) {
  return [{ json: {
    valid: false,
    query: null,
    error: 'OPERATION_BLOCKED: Multiple statements in a single query are not permitted.'
  }}];
}

// ─── Rule 6: No system table access ─────────────────────────
if (/\b(information_schema|performance_schema|mysql|sys)\b/i.test(rawQuery)) {
  return [{ json: {
    valid: false,
    query: null,
    error: 'OPERATION_BLOCKED: Access to database system tables is not permitted.'
  }}];
}

// ─── Rule 7: No file operations ─────────────────────────────
if (/\b(INTO\s+OUTFILE|INTO\s+DUMPFILE|LOAD\s+DATA|LOAD_FILE)\b/i.test(rawQuery)) {
  return [{ json: {
    valid: false,
    query: null,
    error: 'OPERATION_BLOCKED: File read/write operations are not permitted.'
  }}];
}

// ─── Rule 8: No timing or DoS functions ─────────────────────
if (/\b(SLEEP|BENCHMARK|WAIT_FOR_EXECUTED_GTID_SET)\b/i.test(rawQuery)) {
  return [{ json: {
    valid: false,
    query: null,
    error: 'OPERATION_BLOCKED: This query contains functions that are not permitted.'
  }}];
}

// ─── All checks passed ───────────────────────────────────────
return [{ json: { valid: true, query: rawQuery, error: null } }];

const allItems = $input.all();

// Check for error item (from continueOnFail)
if (allItems.length === 1 && allItems[0].json.error) {
  return [{ json: { success: false, error: String(allItems[0].json.error.message || allItems[0].json.error) } }];
}

// Filter out empty passthrough items (0-row results from alwaysOutputData)
const rows = allItems
  .map(i => i.json)
  .filter(r => r && typeof r === 'object' && !r.error && !r.query);

return [{ json: { success: true, rows, count: rows.length } }];
